diff --git a/llvm/lib/Transforms/InstCombine/InstCombineAndOrXor.cpp b/llvm/lib/Transforms/InstCombine/InstCombineAndOrXor.cpp
index 64bee4ab974e..4fd7c2238f21 100644
--- a/llvm/lib/Transforms/InstCombine/InstCombineAndOrXor.cpp
+++ b/llvm/lib/Transforms/InstCombine/InstCombineAndOrXor.cpp
@@ -3358,19 +3358,34 @@ Value *InstCombinerImpl::foldAndOrOfICmps(ICmpInst *LHS, ICmpInst *RHS,
           foldAndOrOfICmpEqConstantAndICmp(LHS, RHS, IsAnd, IsLogical, Builder))
     return V;
   // We can treat logical like bitwise here, because both operands are used on
-  // the LHS, and as such poison from both will propagate.
+  // the LHS, and as such poison from both will propagate. However, if this
+  // causes us to drop short-circuiting and return a single unconditional
+  // compare, we must clear the 'samesign' flag to avoid introducing poison
+  // where the original logical form was guarded.
+  if (IsLogical) {
+    if (auto *IC0 = dyn_cast<ICmpInst>(LHS); IC0 && IC0->hasSameSign())
+      IC0->setSameSign(false);
+    if (auto *IC1 = dyn_cast<ICmpInst>(RHS); IC1 && IC1->hasSameSign())
+      IC1->setSameSign(false);
+  }
   if (Value *V = foldAndOrOfICmpEqConstantAndICmp(RHS, LHS, IsAnd,
-                                                  /*IsLogical*/ false, Builder))
+                                                  /*IsLogical*/ false, Builder)) {
     return V;
+  }

   if (Value *V =
           foldAndOrOfICmpsWithConstEq(LHS, RHS, IsAnd, IsLogical, Builder, Q))
     return V;
   // We can convert this case to bitwise and, because both operands are used
-  // on the LHS, and as such poison from both will propagate.
+  // on the LHS, and as such poison from both will propagate. Same caveat as
+  // above: if we end up with an unconditional compare, drop 'samesign'.
   if (Value *V = foldAndOrOfICmpsWithConstEq(RHS, LHS, IsAnd,
-                                             /*IsLogical*/ false, Builder, Q))
+                                             /*IsLogical*/ false, Builder, Q)) {
+    if (IsLogical)
+      if (auto *IC = dyn_cast<ICmpInst>(V); IC && IC->hasSameSign())
+        IC->setSameSign(false);
     return V;
+  }

   if (Value *V = foldIsPowerOf2OrZero(LHS, RHS, IsAnd, Builder, *this))
     return V;
@@ -3514,7 +3529,17 @@ Value *InstCombinerImpl::foldAndOrOfICmps(ICmpInst *LHS, ICmpInst *RHS,
     }
   }

-  return foldAndOrOfICmpsUsingRanges(LHS, RHS, IsAnd);
+  if (Value *Res = foldAndOrOfICmpsUsingRanges(LHS, RHS, IsAnd)) {
+    // For logical select-form folds, if we collapse to a single compare that
+    // retains a 'samesign' flag, it may now execute unconditionally whereas the
+    // original flagged compare's result was only used conditionally. To avoid
+    // introducing poison, conservatively drop the flag.
+    if (IsLogical)
+      if (auto *IC = dyn_cast<ICmpInst>(Res); IC && IC->hasSameSign())
+        IC->setSameSign(false);
+    return Res;
+  }
+  return nullptr;
 }

 static Value *foldOrOfInversions(BinaryOperator &I,

